"use client"

import * as React from "react"
import type { ColumnDef } from "@gunjo/ui"
import {
  Card,
  CardHeader,
  CardTitle,
  CardDescription,
  CardContent,
  DataTable,
  PersonCell,
  Meter,
  Badge,
  Statistic,
  Separator,
  ApprovalSteps,
  type ApprovalStep,
  Tabs,
  TabsList,
  TabsTrigger,
  TabsContent,
  Button,
  Alert,
  AlertTitle,
  AlertDescription,
  type CoSignValue,
  formatCurrency,
  formatNumber,
} from "@gunjo/ui"
import { IconChevronRight, IconSend, IconFileExport } from "@tabler/icons-react"
import {
  records as seedRecords,
  type BillingRecord,
  type ServiceLine,
  type FuturanaStatus,
  summarize,
  workflowSteps,
  careLevelTone,
  submitDeadline,
} from "./data"
import { DetailSheet } from "./DetailSheet"

const STATUS_TONE: Record<FuturanaStatus, "secondary" | "info" | "success" | "destructive"> = {
  未確定: "secondary",
  確定: "info",
  伝送済: "success",
  返戻: "destructive",
}

export function BillingClient() {
  // 利用者明細は編集可能なので state で保持。
  const [records, setRecords] = React.useState<BillingRecord[]>(seedRecords)
  const [openId, setOpenId] = React.useState<string | null>(null)
  // 確定サインオフ（利用者ごと）
  const [signoffs, setSignoffs] = React.useState<Record<string, CoSignValue>>({})

  const active = records.find((r) => r.id === openId) ?? null

  // ── 全体サマリ集計 ──
  const totals = React.useMemo(() => {
    let gross = 0
    let insurance = 0
    let copay = 0
    let over = 0
    let unconfirmed = 0
    let returned = 0
    for (const r of records) {
      const s = summarize(r)
      gross += s.grossYen
      insurance += s.insuranceYen
      copay += s.copayYen
      if (s.limitUtil > 1) over += 1
      if (r.status === "未確定") unconfirmed += 1
      if (r.status === "返戻") returned += 1
    }
    return { gross, insurance, copay, over, unconfirmed, returned, count: records.length }
  }, [records])

  const updateLines = (recId: string, lines: ServiceLine[]) => {
    setRecords((prev) => prev.map((r) => (r.id === recId ? { ...r, lines } : r)))
  }

  const confirmRecord = (recId: string) => {
    setRecords((prev) =>
      prev.map((r) => (r.id === recId && r.status === "未確定" ? { ...r, status: "確定" } : r))
    )
  }

  // ── 読み取り用スキャン表（請求明細一覧） ──
  const columns: ColumnDef<BillingRecord>[] = [
    {
      id: "name",
      header: "利用者",
      cell: ({ row }) => {
        const r = row.original
        return (
          <PersonCell
            name={r.name}
            secondary={`${r.kana}・${r.age}歳`}
            tertiary={`被保番 ${r.insuredNumber}`}
            size="sm"
            avatarClassName="bg-secondary text-secondary-foreground"
            trailing={<Badge variant={careLevelTone[r.careLevel]}>{r.careLevel}</Badge>}
          />
        )
      },
    },
    {
      id: "copay",
      header: "負担",
      cell: ({ row }) => (
        <span className="whitespace-nowrap text-sm tabular-nums">{row.original.copayRate}割</span>
      ),
    },
    {
      id: "insurance",
      header: "国保連請求額",
      cell: ({ row }) => (
        <span className="block text-right font-medium tabular-nums">
          {formatCurrency(summarize(row.original).insuranceYen)}
        </span>
      ),
    },
    {
      id: "copayYen",
      header: "利用者負担額",
      cell: ({ row }) => (
        <span className="block text-right tabular-nums text-muted-foreground">
          {formatCurrency(summarize(row.original).copayYen)}
        </span>
      ),
    },
    {
      id: "limit",
      header: "限度額利用率",
      cell: ({ row }) => {
        const s = summarize(row.original)
        return (
          <div className="min-w-[7rem]">
            <Meter
              size="inline"
              value={s.totalUnits}
              max={row.original.limitUnits}
              thresholds={{ warning: 0.9, over: 1 }}
              label={`${row.original.name} 限度額利用率`}
            />
          </div>
        )
      },
    },
    {
      id: "status",
      header: "状態",
      cell: ({ row }) => (
        <div className="flex items-center justify-end gap-1">
          <Badge variant={STATUS_TONE[row.original.status]}>{row.original.status}</Badge>
          <IconChevronRight className="h-4 w-4 text-muted-foreground" aria-hidden />
        </div>
      ),
    },
  ]

  const approvalSteps: ApprovalStep[] = workflowSteps.map((s) => ({
    label: s.label,
    state: s.state,
    actor: s.actor,
    timestamp: s.timestamp,
  }))

  // モバイル用カード
  const renderCard = (r: BillingRecord) => {
    const s = summarize(r)
    return (
      <div className="flex flex-col gap-2">
        <PersonCell
          name={r.name}
          secondary={`${r.kana}・${r.age}歳・${r.copayRate}割`}
          size="sm"
          avatarClassName="bg-secondary text-secondary-foreground"
          trailing={<Badge variant={STATUS_TONE[r.status]}>{r.status}</Badge>}
        />
        <div className="flex items-center justify-between text-sm">
          <span className="text-muted-foreground">国保連請求</span>
          <span className="font-medium tabular-nums">{formatCurrency(s.insuranceYen)}</span>
        </div>
        <div className="flex items-center justify-between text-sm">
          <span className="text-muted-foreground">利用者負担</span>
          <span className="tabular-nums">{formatCurrency(s.copayYen)}</span>
        </div>
        <Meter
          size="inline"
          value={s.totalUnits}
          max={r.limitUnits}
          thresholds={{ warning: 0.9, over: 1 }}
          label={`${r.name} 限度額利用率`}
        />
        <Badge variant={careLevelTone[r.careLevel]} className="w-fit">{r.careLevel}</Badge>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      {/* サマリ指標 */}
      <section aria-label="請求月サマリ" className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-4">
        <Card>
          <CardContent className="pt-5">
            <Statistic label="請求対象者" value={`${totals.count}名`} hint={`未確定 ${totals.unconfirmed}件`} />
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-5">
            <Statistic
              label="請求総額（費用）"
              value={formatCurrency(totals.gross)}
              hint="介護給付＋利用者負担"
            />
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-5">
            <Statistic label="国保連請求分" value={formatCurrency(totals.insurance)} hint="介護給付費" />
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-5">
            <Statistic label="利用者負担分" value={formatCurrency(totals.copay)} hint="窓口徴収" />
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-5">
            <Statistic
              label="限度額超過者"
              value={`${totals.over}名`}
              tone={totals.over > 0 ? "negative" : "neutral"}
              hint="区分支給限度基準額"
            />
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-5">
            <Statistic
              label="返戻件数"
              value={`${totals.returned}件`}
              tone={totals.returned > 0 ? "negative" : "neutral"}
              hint="要再請求"
            />
          </CardContent>
        </Card>
        <Card>
          <CardContent className="pt-5">
            <Statistic label="未確定件数" value={`${totals.unconfirmed}件`} hint="確定待ち" />
          </CardContent>
        </Card>
        <Card className="border-warning-border">
          <CardContent className="pt-5">
            <Statistic label="国保連 提出期限" value={submitDeadline} hint="毎月10日締め" />
          </CardContent>
        </Card>
      </section>

      {(totals.over > 0 || totals.returned > 0) && (
        <Alert variant="warning">
          <AlertTitle>確定前の要対応があります</AlertTitle>
          <AlertDescription>
            限度額超過 {totals.over}名・返戻 {totals.returned}件。該当者の行を開いて内容を確認し、必要に応じて回数を調整・再請求してください。
          </AlertDescription>
        </Alert>
      )}

      <Tabs defaultValue="detail">
        <TabsList>
          <TabsTrigger value="detail">請求明細</TabsTrigger>
          <TabsTrigger value="workflow">国保連伝送</TabsTrigger>
        </TabsList>

        <TabsContent value="detail" className="p-4">
          <Card>
            <CardHeader>
              <CardTitle>利用者ごとの請求明細</CardTitle>
              <CardDescription>
                行を開いて実績の確認・限度額チェック・回数調整・2人確認による確定を行います。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <DataTable
                columns={columns}
                data={records}
                filter={{ columnId: "name", placeholder: "利用者名で絞り込み" }}
                onRowClick={(r) => setOpenId(r.id)}
                renderCard={renderCard}
                pageSize={10}
              />
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="workflow" className="p-4">
          <Card>
            <CardHeader>
              <CardTitle>国保連伝送ワークフロー</CardTitle>
              <CardDescription>{submitDeadline} までに伝送を完了してください。</CardDescription>
            </CardHeader>
            <CardContent className="space-y-5">
              <ApprovalSteps
                steps={approvalSteps}
                stateLabels={{
                  approved: "完了",
                  current: "対応中",
                  pending: "未着手",
                  rejected: "差戻し",
                  skipped: "スキップ",
                }}
              />
              <Separator />
              <div className="flex flex-wrap gap-3">
                <Button disabled={totals.unconfirmed > 0}>
                  <IconFileExport className="h-4 w-4" />
                  国保連請求データ（CSV）を作成
                </Button>
                <Button variant="outline" disabled={totals.unconfirmed > 0}>
                  <IconSend className="h-4 w-4" />
                  電子請求受付システムへ伝送
                </Button>
              </div>
              {totals.unconfirmed > 0 ? (
                <p className="text-xs text-muted-foreground">
                  未確定が {totals.unconfirmed}件 残っています。すべて確定するとデータ作成・伝送に進めます。
                </p>
              ) : null}
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>

      <DetailSheet
        record={active}
        open={openId !== null}
        onOpenChange={(o) => setOpenId(o ? openId : null)}
        lines={active?.lines ?? []}
        onLinesChange={(lines) => active && updateLines(active.id, lines)}
        cosign={active ? signoffs[active.id] : undefined}
        onCosign={(v) => active && setSignoffs((prev) => ({ ...prev, [active.id]: v }))}
        onConfirm={() => active && confirmRecord(active.id)}
      />
    </div>
  )
}

"use client"

import * as React from "react"
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
  EditableDataTable,
  type EditableColumn,
  NumberInput,
  Meter,
  Badge,
  Statistic,
  Delta,
  Separator,
  CoSign,
  type CoSignValue,
  MetadataList,
  Alert,
  AlertTitle,
  AlertDescription,
  formatCurrency,
  formatNumber,
} from "@gunjo/ui"
import {
  type BillingRecord,
  type ServiceLine,
  summarize,
  benefitRate,
  careLevelTone,
  supervisorId,
} from "./data"

interface DetailSheetProps {
  record: BillingRecord | null
  open: boolean
  onOpenChange: (open: boolean) => void
  lines: ServiceLine[]
  onLinesChange: (lines: ServiceLine[]) => void
  cosign?: CoSignValue
  onCosign: (value: CoSignValue) => void
  onConfirm: () => void
}

export function DetailSheet({
  record,
  open,
  onOpenChange,
  lines,
  onLinesChange,
  cosign,
  onCosign,
  onConfirm,
}: DetailSheetProps) {
  if (!record) return null

  const working: BillingRecord = { ...record, lines }
  const sum = summarize(working)
  const baseSum = summarize(record)
  const isOver = sum.limitUtil > 1

  const setCount = (lineId: string, count: number) => {
    onLinesChange(lines.map((l) => (l.id === lineId ? { ...l, count } : l)))
  }

  const columns: EditableColumn<ServiceLine>[] = [
    {
      id: "service",
      header: "サービス種類 / コード",
      width: "16rem",
      cell: (row) => (
        <div className="min-w-0">
          <div className="truncate font-medium text-foreground">{row.serviceName}</div>
          <div className="text-xs tabular-nums text-muted-foreground">{row.serviceCode}</div>
        </div>
      ),
    },
    {
      id: "units",
      header: "単位数",
      headerLabel: "単位数",
      align: "right",
      width: "6rem",
      cell: (row) => <span className="tabular-nums">{formatNumber(row.unitsPer)}</span>,
    },
    {
      id: "count",
      header: "回数",
      headerLabel: "回数",
      align: "right",
      width: "8rem",
      cell: (row, ctx) => (
        <NumberInput
          value={row.count}
          min={0}
          max={62}
          aria-label={ctx.ariaLabel}
          onValueChange={(v) => setCount(row.id, v)}
          className="w-full"
        />
      ),
    },
    {
      id: "subUnits",
      header: "小計単位",
      headerLabel: "小計単位",
      align: "right",
      width: "7rem",
      cell: (row) => (
        <span className="tabular-nums">{formatNumber(row.unitsPer * row.count)}</span>
      ),
    },
    {
      id: "amount",
      header: "費用額",
      headerLabel: "費用額",
      align: "right",
      width: "8rem",
      cell: (row) => (
        <span className="tabular-nums">
          {formatCurrency(Math.floor(row.unitsPer * row.count * row.unitPrice))}
        </span>
      ),
    },
  ]

  const totalUnits = sum.totalUnits
  const unitsDelta = totalUnits - baseSum.totalUnits

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent side="right" className="flex w-full flex-col gap-0 overflow-y-auto sm:max-w-2xl">
        <SheetHeader className="space-y-1">
          <div className="flex flex-wrap items-center gap-2">
            <Badge variant={careLevelTone[record.careLevel]}>{record.careLevel}</Badge>
            <Badge variant="outline">利用者負担 {record.copayRate}割</Badge>
            <Badge variant="outline">給付率 {Math.round(benefitRate(record.copayRate) * 100)}%</Badge>
          </div>
          <SheetTitle className="text-xl">
            {record.name}
            <span className="ml-2 text-sm font-normal text-muted-foreground">{record.kana}・{record.age}歳</span>
          </SheetTitle>
          <SheetDescription>
            被保険者番号 {record.insuredNumber}　給付管理：{record.planSource}
          </SheetDescription>
        </SheetHeader>

        <div className="flex flex-col gap-6 px-1 py-2">
          {record.status === "返戻" && record.returnReason ? (
            <Alert variant="destructive">
              <AlertTitle>返戻（{record.returnCode}）— 再請求が必要です</AlertTitle>
              <AlertDescription>{record.returnReason}</AlertDescription>
            </Alert>
          ) : null}

          {/* 区分支給限度額チェック */}
          <section aria-labelledby="limit-heading" className="space-y-2">
            <h3 id="limit-heading" className="text-sm font-semibold text-foreground">
              区分支給限度基準額チェック
            </h3>
            <Meter
              label="区分支給限度基準額に対する利用"
              value={totalUnits}
              max={record.limitUnits}
              thresholds={{ warning: 0.9, over: 1 }}
              formatValue={(n) => `${formatNumber(Math.round(n))}単位`}
            />
            {isOver ? (
              <p className="text-xs font-medium text-destructive">
                限度額を {formatNumber(sum.overUnits)} 単位超過。超過分（約{formatCurrency(Math.floor(sum.overUnits * 10.45))}）は全額利用者負担となります。サービス回数の見直しが必要です。
              </p>
            ) : (
              <p className="text-xs text-muted-foreground">
                残り {formatNumber(Math.max(0, record.limitUnits - totalUnits))} 単位（利用率 {Math.round(sum.limitUtil * 100)}%）。
              </p>
            )}
          </section>

          <Separator />

          {/* 編集可能なサービス提供実績明細 */}
          <section aria-labelledby="detail-heading" className="space-y-3">
            <div className="flex items-baseline justify-between">
              <h3 id="detail-heading" className="text-sm font-semibold text-foreground">
                サービス提供実績明細（回数を確認・調整）
              </h3>
              {unitsDelta !== 0 ? (
                <Delta
                  value={unitsDelta}
                  format={(v) => `${formatNumber(Math.abs(v))}単位`}
                  labels={{ positive: "増加", negative: "減少", zero: "変更なし" }}
                  showLabel
                />
              ) : null}
            </div>
            <EditableDataTable
              columns={columns}
              rows={lines}
              getRowId={(l) => l.id}
              variant="default"
              rowLabel={(i) => lines[i]?.serviceName ?? `明細 ${i + 1}`}
              getRowError={(l) =>
                l.count < 0 ? "回数が不正です" : undefined
              }
              renderFooterCell={(col) => {
                if (col.id === "service") return <span className="text-xs text-muted-foreground">合計</span>
                if (col.id === "subUnits") return <span className="tabular-nums">{formatNumber(totalUnits)}</span>
                if (col.id === "amount") return <span className="tabular-nums">{formatCurrency(sum.grossYen)}</span>
                return null
              }}
              caption="回数は実績に基づき調整できます。確定前に必ず給付管理票と突合してください。"
            />
          </section>

          <Separator />

          {/* 保険／負担内訳 */}
          <section aria-labelledby="breakdown-heading" className="space-y-3">
            <h3 id="breakdown-heading" className="text-sm font-semibold text-foreground">
              請求内訳
            </h3>
            <div className="grid grid-cols-2 gap-4 sm:grid-cols-3">
              <Statistic label="費用総額" value={formatCurrency(sum.grossYen)} />
              <Statistic
                label="国保連請求（介護給付）"
                value={formatCurrency(sum.insuranceYen)}
                hint={`給付率 ${Math.round(sum.rate * 100)}%`}
              />
              <Statistic
                label="利用者負担"
                value={formatCurrency(sum.copayYen)}
                hint={`${record.copayRate}割`}
              />
            </div>
            <MetadataList
              items={[
                { label: "サービス提供月", value: "2026年5月分" },
                { label: "給付管理票", value: record.planSource },
                { label: "合計単位数", value: `${formatNumber(totalUnits)} 単位` },
                { label: "限度額に対する利用率", value: `${Math.round(sum.limitUtil * 100)}%` },
              ]}
            />
          </section>

          <Separator />

          {/* 確定・2人確認サインオフ */}
          <section aria-labelledby="signoff-heading" className="space-y-3 pb-6">
            <h3 id="signoff-heading" className="text-sm font-semibold text-foreground">
              明細確定（管理者2人確認）
            </h3>
            <CoSign
              primaryId={"umehara"}
              value={cosign}
              requireReason={isOver}
              attestations={[
                { id: "att-1", label: "給付管理票の計画単位数とサービス提供実績が一致していることを確認した" },
                { id: "att-2", label: "区分支給限度基準額の超過有無を確認した" },
                { id: "att-3", label: "利用者負担割合・給付率が受給者証と一致していることを確認した" },
              ]}
              signerLabel="管理者ID（2人目確認）"
              reasonLabel="限度額超過の確認理由・備考"
              onSign={(v) => {
                onCosign(v)
                onConfirm()
              }}
              labels={{
                sign: "確認して明細を確定",
                signed: "明細確定済み（2人確認）",
                pending: "管理者の2人目確認が必要です",
              }}
            />
            <p className="text-xs text-muted-foreground">
              主担当：梅原 智子。2人目は管理者（{supervisorId} 等）が確認します。確定後は国保連請求データ作成へ進めます。
            </p>
          </section>
        </div>
      </SheetContent>
    </Sheet>
  )
}
